14→- tests: Writing, updating, or fixing tests
15→
16→CRITICAL: Respond with ONLY the tag name. Nothing else. No explanation, no punctuation, no formatting. Just ONE of: research, new_feature, bug_fix, refactoring, documentation, tests`;
17→
18→/**
19→ * Classify a session transcript using Claude CLI.
20→ * Returns one of the predefined tags based on the session content.
21→ */
22→export async function classifySession(
23→	content: string,
24→): Promise<SessionTag | undefined> {
25→	// Truncate content to avoid excessive API costs
26→	const truncatedContent = content.slice(0, 50000);
27→
28→	const tempDir = join(homedir(), ".claude", "temp");
29→	const tempFile = join(tempDir, `classify-${Date.now()}.txt`);
30→
31→	try {
32→		await mkdir(tempDir, { recursive: true });
33→		await writeFile(
34→			tempFile,
35→			`Classify this session transcript:\n\n${truncatedContent}`,
36→		);
37→
38→		const prompt = `Read and classify the session transcript in this file: ${tempFile}`;
39→		const escapedPrompt = prompt.replace(/'/g, "'\\''");
40→		const escapedSystemPrompt = SYSTEM_PROMPT.replace(/'/g, "'\\''");
41→
42→		const result = await exec("sh", [
43→			"-c",
44→			`echo '${escapedPrompt}' | claude --output-format text --print --model haiku --no-session-persistence --dangerously-skip-permissions --system-prompt '${escapedSystemPrompt}'`,
45→		]);
46→
47→		if (result.exitCode !== 0) {
48→			return "other";
49→		}
50→
51→		const output = result.stdout.trim().toLowerCase();
52→
53→		// Exact match
54→		if (SESSION_TAGS.includes(output as SessionTag)) {
55→			return output as SessionTag;
56→		}
57→
58→		// Search for valid tags in verbose output
59→		for (const tag of SESSION_TAGS) {
60→			if (new RegExp(`\\b${tag}\\b`).test(output)) {
61→				return tag;
62→			}
63→		}
64→
65→		return "other";
66→	} catch {
67→		return undefined;
68→	} finally {
69→		try {
70→			await unlink(tempFile);
71→		} catch {
72→			// Ignore cleanup errors
73→		}
74→	}
75→}
76→

